index 9ff1e3aa5502..065906827772 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4804,6 +4804,23 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,

   if (Instruction *NewICmp = foldICmpXNegX(I, Builder))
     return NewICmp;
+  // icmp (sdiv X, C), X
+  const APInt *DivC;
+  if (match(Op0, m_SDiv(m_Specific(Op1), m_APInt(DivC))) &&
+      !DivC->isZero() && !DivC->isOne() && !DivC->isAllOnes()) {
+    const CmpInst::Predicate Pred = I.getPredicate();
+    if (Pred == ICmpInst::ICMP_SLT)
+      return new ICmpInst(ICmpInst::ICMP_SGT, Op1, ConstantInt::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SGT)
+      return new ICmpInst(ICmpInst::ICMP_SLT, Op1, ConstantInt::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SLE)
+      return new ICmpInst(ICmpInst::ICMP_SGE, Op1, ConstantInt::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_SGE)
+    if (Pred == ICmpInst::ICMP_EQ)
+      return new ICmpInst(ICmpInst::ICMP_EQ, Op1, ConstantInt::getNullValue(Op1->getType()));
+    if (Pred == ICmpInst::ICMP_NE)
+      return new ICmpInst(ICmpInst::ICMP_NE, Op1, ConstantInt::getNullValue(Op1->getType()));
+  }

   const CmpInst::Predicate Pred = I.getPredicate();
   Value *X;

