   if (Instruction *NewICmp = foldICmpXNegX(I, Builder))
     return NewICmp;

+  // icmp (sdiv X, C), X
+  const APInt *DivC;
+  if (match(Op0, m_SDiv(m_Specific(Op1), m_APInt(DivC))) &&
+      !DivC->isZero() && !DivC->isOne() && !DivC->isAllOnes()) {
+    const CmpInst::Predicate Pred = I.getPredicate();
+    
+    // For C > 1 or C < -1, the quotient is smaller in magnitude than X.
+    // X > 0: sdiv X, C is positive (C>1) or negative (C<-1) and its magnitude is < X.
+    //       So for C>1:  sdiv < X.  For C<-1: sdiv < X (since sdiv is negative and X is positive, negative < positive is true).
+    // X < 0: sdiv X, C is negative (C>1) or positive (C<-1) and its magnitude is < |X|.
+    //       So for C>1:  sdiv > X.  For C<-1: sdiv > X (since sdiv is positive and X is negative).
+    // X = 0: sdiv = 0 = X.
+    
+    // So for both C>1 and C<-1:
+    // sdiv < X  <=> X > 0
+    // sdiv > X  <=> X < 0
+    // sdiv <= X <=> X >= 0
+    // sdiv >= X <=> X <= 0
+    // sdiv == X <=> X == 0
+    // sdiv != X <=> X != 0
+    
+    if (Pred == ICmpInst::ICMP_SLT)
